def base_tokens(s):
    toks = token_set(s)
    # remove leading 'و' and 'ال' from tokens
    def strip_prefix(t):
        tt = t
        if tt.startswith('ال') and len(tt) > 2:
            tt = tt[2:]
        if tt.startswith('و') and len(tt) > 1:
            tt = tt[1:]
        return tt
    return set(strip_prefix(t) for t in toks if t)

